if ((#MultiButton #Hallway).multiButton_button2 == "pushed") {
if (triggered == false) {
tmp = (#Light #Hallway).light_currentBrightness - 10
        if (0 < tmp) {
tmp = 0
}
(#Light #Hallway).light_moveToBrightness(tmp, 0)
        triggered = true
}
}
else {
triggered = false
}

